SELECT U.ESNTL_ID
  FROM ARMUSER U
 WHERE DECRYPT(U.USER_NM) = #{userNm}
   AND U.SEXDSTN_CODE = #{sexdstnCode}
   AND DECRYPT(U.MBTLNUM) = #{mbtlnum}
   AND (DECRYPT(U.IHIDNUM) = #{ihidnum} OR U.IHIDNUM = #{ihidnum})
 LIMIT 1

SELECT 1
  FROM ARMCHIL
 WHERE P_ESNTL_ID = #{pEsntlId}
   AND C_ESNTL_ID = #{cEsntlId}
 LIMIT 1

mapper.delete:
DELETE FROM ARMCHIL
 WHERE P_ESNTL_ID = #{pEsntlId}
   AND C_ESNTL_ID = #{cEsntlId}
